const raw = await fs.readFile(toolsPath, "utf8");
const data = JSON.parse(raw);
const missing = [];

for (const tool of data.tools) {
  const governance = GOVERNANCE[tool.id];
  if (!governance) {
    missing.push(tool.id);
    continue;
  }
  tool.governance = { ...governance, reviewedAt: REVIEWED };
}

const extra = Object.keys(GOVERNANCE).filter((id) => !data.tools.some((tool) => tool.id === id));

if (missing.length > 0 || extra.length > 0) {
  if (missing.length > 0) console.error(`Tools missing governance entries: ${missing.join(", ")}`);
  if (extra.length > 0) console.error(`Governance entries with no matching tool: ${extra.join(", ")}`);
  process.exit(1);
}

await fs.writeFile(toolsPath, `${JSON.stringify(data, null, 2)}\n`);
console.log(`Applied governance posture to ${data.tools.length} tools.`);
